"/* DESIGN SYSTEM & ROOT VARIABLES */
:root {
    --primary-dark: #10321c;    /* Deep forest green for sidebar */
    --primary-medium: #154726;  /* Brand dark green for headers/buttons */
    --primary-light: #226436;   /* Active button state */
    --primary-accent: #2e7d32;  /* Vibrant accent green for badges/logos */
    --primary-hover: #3b8c3b;   /* Hover accent */

    --text-dark: #111827;       /* Charcoal for primary headings */
    --text-medium: #374151;     /* Gray-700 for body text and labels */
    --text-light: #6b7280;      /* Gray-500 for secondary text and hints */
    --border-color: #e5e7eb;    /* Light gray border */

    --bg-light: #f9fafb;        /* App dashboard background background */
    --bg-white: #ffffff;

    --success-bg: #ecfdf5;
    --success-text: #047857;
    --success-border: #a7f3d0;

    --warning-bg: #fffbeb;
    --warning-text: #b45309;
    --warning-border: #fde68a;

    --danger-bg: #fef2f2;
    --danger-text: #b91c1c;
    --danger-border: #fca5a5;

    --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
    --transition-fast: 0.15s ease;
    --transition-normal: 0.25s cubic-bezier(0.4, 0, 0.2, 1);
    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
    --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
}

/* GENERAL BASE STYLES */
* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-sans);
    color: var(--text-medium);
    background-color: var(--bg-light);
    line-height: 1.5;
    overflow-x: hidden;
    height: 100vh;
}

/* PAGE WRAPPERS & TRANSITIONS */
.page {
    display: none;
    opacity: 0;
    transform: translateY(10px);
    transition: opacity var(--transition-normal), transform var(--transition-normal);
    height: 100vh;
    width: 100vw;
}

